    def __init__(self):
        raise NotImplementedError

    def push(self, x):
        """Push x onto the top."""
        raise NotImplementedError

    def pop(self):
        """Remove and return the top item. Raise IndexError if empty."""
        raise NotImplementedError

    def peek(self):
        """Return (without removing) the top item. Raise IndexError if empty."""
        raise NotImplementedError

    def is_empty(self):
        """Return True iff the stack has no items."""
        raise NotImplementedError

    def __len__(self):
        raise NotImplementedError
